INSERT INTO questions (subject, topic, difficulty, question_text, choices, correct_answer, explanation, exam_type) VALUES
('General Education','Mathematics','easy','What is the Greatest Common Factor (GCF) of 48 and 72?','[{"key":"A","text":"6"},{"key":"B","text":"12"},{"key":"C","text":"24"},{"key":"D","text":"36"}]','C','Factors of 48: 1,2,3,4,6,8,12,16,24,48. Factors of 72: 1,2,3,4,6,8,9,12,18,24,36,72. GCF = 24.','secondary'),
('General Education','Mathematics','easy','What is the Least Common Multiple (LCM) of 4 and 6?','[{"key":"A","text":"2"},{"key":"B","text":"12"},{"key":"C","text":"24"},{"key":"D","text":"10"}]','B','Multiples of 4: 4,8,12... Multiples of 6: 6,12... The smallest common multiple is 12.','secondary'),
('General Education','Mathematics','easy','Which of the following is a prime number?','[{"key":"A","text":"1"},{"key":"B","text":"9"},{"key":"C","text":"15"},{"key":"D","text":"17"}]','D','A prime number has exactly two distinct factors: 1 and itself. 17 is divisible only by 1 and 17. (1 is not prime; 9 = 3×3; 15 = 3×5.)','secondary'),
('General Education','Mathematics','medium','What is the value of 3² + 4²?','[{"key":"A","text":"7"},{"key":"B","text":"14"},{"key":"C","text":"25"},{"key":"D","text":"49"}]','C','3² = 9, 4² = 16. 9 + 16 = 25. (Note: this also illustrates the 3-4-5 Pythagorean triple.)','secondary'),
('General Education','Mathematics','easy','Simplify: 5/8 + 1/4','[{"key":"A","text":"6/12"},{"key":"B","text":"7/8"},{"key":"C","text":"3/4"},{"key":"D","text":"6/8"}]','B','Convert 1/4 to 2/8. Then 5/8 + 2/8 = 7/8.','secondary'),
('General Education','Mathematics','easy','What is 15% of 200?','[{"key":"A","text":"15"},{"key":"B","text":"20"},{"key":"C","text":"30"},{"key":"D","text":"45"}]','C','15% × 200 = 0.15 × 200 = 30.','secondary'),
('General Education','Mathematics','medium','A shirt originally costs ₱500 and is sold at a 20% discount. What is the sale price?','[{"key":"A","text":"₱400"},{"key":"B","text":"₱450"},{"key":"C","text":"₱480"},{"key":"D","text":"₱420"}]','A','Discount = 20% × ₱500 = ₱100. Sale price = ₱500 - ₱100 = ₱400.','secondary'),
('General Education','Mathematics','easy','Evaluate: 2³ × 2²','[{"key":"A","text":"2⁵"},{"key":"B","text":"2⁶"},{"key":"C","text":"4⁵"},{"key":"D","text":"2¹"}]','A','When multiplying powers with the same base, add the exponents: 2³ × 2² = 2^(3+2) = 2⁵ = 32.','secondary'),
('General Education','Mathematics','medium','Convert 0.375 to a fraction in lowest terms.','[{"key":"A","text":"3/8"},{"key":"B","text":"375/1000"},{"key":"C","text":"3/4"},{"key":"D","text":"1/3"}]','A','0.375 = 375/1000 = 3/8 (dividing numerator and denominator by 125).','secondary'),
('General Education','Mathematics','easy','What is the value of |-15|?','[{"key":"A","text":"-15"},{"key":"B","text":"0"},{"key":"C","text":"15"},{"key":"D","text":"1/15"}]','C','The absolute value of a number is its distance from zero; it is always non-negative. |-15| = 15.','secondary'),
('General Education','Mathematics','easy','Which of the following is NOT a factor of 36?','[{"key":"A","text":"4"},{"key":"B","text":"6"},{"key":"C","text":"8"},{"key":"D","text":"9"}]','C','Factors of 36: 1, 2, 3, 4, 6, 9, 12, 18, 36. 8 does not divide 36 evenly (36 ÷ 8 = 4.5).','secondary'),
('General Education','Mathematics','medium','The ratio of boys to girls in a class is 3:5. If there are 40 students, how many are boys?','[{"key":"A","text":"15"},{"key":"B","text":"24"},{"key":"C","text":"25"},{"key":"D","text":"20"}]','A','Total parts = 3 + 5 = 8. Boys = (3/8) × 40 = 15.','secondary'),
('General Education','Mathematics','easy','What is -8 × (-3)?','[{"key":"A","text":"-24"},{"key":"B","text":"24"},{"key":"C","text":"-11"},{"key":"D","text":"11"}]','B','The product of two negative numbers is positive: (-8) × (-3) = 24.','secondary'),
('General Education','Mathematics','medium','Simplify: (2x³)(3x²)','[{"key":"A","text":"5x⁵"},{"key":"B","text":"6x⁵"},{"key":"C","text":"6x⁶"},{"key":"D","text":"5x⁶"}]','B','Multiply coefficients: 2 × 3 = 6. Add exponents: x³ × x² = x⁵. Result: 6x⁵.','secondary'),
('General Education','Mathematics','easy','What is the square root of 144?','[{"key":"A","text":"11"},{"key":"B","text":"12"},{"key":"C","text":"13"},{"key":"D","text":"14"}]','B','√144 = 12, because 12 × 12 = 144.','secondary'),
('General Education','Mathematics','medium','A car travels 120 km in 2 hours. What is its average speed?','[{"key":"A","text":"40 km/h"},{"key":"B","text":"50 km/h"},{"key":"C","text":"60 km/h"},{"key":"D","text":"80 km/h"}]','C','Speed = Distance ÷ Time = 120 km ÷ 2 h = 60 km/h.','secondary'),
('General Education','Mathematics','hard','What is the remainder when 2^100 is divided by 3?','[{"key":"A","text":"0"},{"key":"B","text":"1"},{"key":"C","text":"2"},{"key":"D","text":"3"}]','B','Powers of 2 mod 3 cycle: 2¹=2, 2²=1, 2³=2, 2⁴=1... Even powers give remainder 1. Since 100 is even, 2^100 mod 3 = 1.','secondary'),
('General Education','Mathematics','easy','Evaluate: 4 + 3 × 2 − 1','[{"key":"A","text":"13"},{"key":"B","text":"9"},{"key":"C","text":"10"},{"key":"D","text":"14"}]','B','By order of operations (PEMDAS): 3 × 2 = 6 first, then 4 + 6 - 1 = 9.','secondary'),
('General Education','Mathematics','medium','What is the next number in the sequence: 2, 6, 18, 54, ___?','[{"key":"A","text":"108"},{"key":"B","text":"162"},{"key":"C","text":"72"},{"key":"D","text":"216"}]','B','Each term is multiplied by 3: 2×3=6, 6×3=18, 18×3=54, 54×3=162.','secondary'),
('General Education','Mathematics','easy','What is 7/8 − 1/4 expressed in lowest terms?','[{"key":"A","text":"6/8"},{"key":"B","text":"5/8"},{"key":"C","text":"3/4"},{"key":"D","text":"1/2"}]','B','Convert 1/4 to 2/8. Then 7/8 − 2/8 = 5/8 (already in lowest terms).','secondary'),
('General Education','Mathematics','medium','If 3x = 21, what is x?','[{"key":"A","text":"3"},{"key":"B","text":"7"},{"key":"C","text":"9"},{"key":"D","text":"6"}]','B','Divide both sides by 3: x = 21 ÷ 3 = 7.','secondary'),
('General Education','Mathematics','medium','A store marks up a product by 25% from its cost of ₱800. What is the selling price?','[{"key":"A","text":"₱1,000"},{"key":"B","text":"₱900"},{"key":"C","text":"₱1,100"},{"key":"D","text":"₱950"}]','A','Markup = 25% × ₱800 = ₱200. Selling price = ₱800 + ₱200 = ₱1,000.','secondary'),
('General Education','Mathematics','easy','Which property is illustrated by: a + (b + c) = (a + b) + c?','[{"key":"A","text":"Commutative"},{"key":"B","text":"Distributive"},{"key":"C","text":"Identity"},{"key":"D","text":"Associative"}]','D','The associative property states that grouping does not affect the sum or product.','secondary'),
('General Education','Mathematics','hard','What is the units digit of 7^99?','[{"key":"A","text":"1"},{"key":"B","text":"3"},{"key":"C","text":"7"},{"key":"D","text":"9"}]','C','Units digits of powers of 7 cycle in groups of 4: 7,9,3,1,7,9,3,1... 99 mod 4 = 3, so the 3rd in the cycle is 3... Actually: 7¹=7, 7²=49, 7³=343, 7⁴=2401 → cycle is 7,9,3,1. 99 = 4×24+3 so the 3rd digit in the cycle is 3.','secondary'),
('General Education','Mathematics','medium','Which of the following is the scientific notation for 0.00045?','[{"key":"A","text":"4.5 × 10⁻⁴"},{"key":"B","text":"4.5 × 10⁴"},{"key":"C","text":"45 × 10⁻⁵"},{"key":"D","text":"0.45 × 10⁻³"}]','A','Move the decimal 4 places to the right: 0.00045 = 4.5 × 10⁻⁴. Standard scientific notation has one non-zero digit before the decimal.','secondary'),
('General Education','Mathematics','easy','What is 40% of 80?','[{"key":"A","text":"24"},{"key":"B","text":"28"},{"key":"C","text":"32"},{"key":"D","text":"36"}]','C','40% × 80 = 0.40 × 80 = 32.','secondary'),
('General Education','Mathematics','medium','Find the missing number: 5 : 20 = 7 : ___','[{"key":"A","text":"21"},{"key":"B","text":"28"},{"key":"C","text":"35"},{"key":"D","text":"14"}]','B','Set up the proportion: 5/20 = 7/x. Cross-multiply: 5x = 140. x = 28.','secondary'),
('General Education','Mathematics','easy','What is the reciprocal of 3/7?','[{"key":"A","text":"7/3"},{"key":"B","text":"3/7"},{"key":"C","text":"21"},{"key":"D","text":"1/21"}]','A','The reciprocal of a fraction is obtained by flipping numerator and denominator: reciprocal of 3/7 = 7/3.','secondary'),
('General Education','Mathematics','hard','How many integers from 1 to 100 are divisible by both 3 and 5?','[{"key":"A","text":"5"},{"key":"B","text":"6"},{"key":"C","text":"7"},{"key":"D","text":"10"}]','B','Numbers divisible by both 3 and 5 must be divisible by LCM(3,5) = 15. Multiples of 15 up to 100: 15,30,45,60,75,90 — that is 6 numbers.','secondary'),
('General Education','Mathematics','medium','A worker completes a job in 6 days. Working together with a partner, they finish in 4 days. How many days does the partner need alone?','[{"key":"A","text":"8"},{"key":"B","text":"10"},{"key":"C","text":"12"},{"key":"D","text":"14"}]','C','Worker''s rate = 1/6 per day. Combined rate = 1/4 per day. Partner''s rate = 1/4 - 1/6 = 1/12 per day. Partner needs 12 days alone.','secondary'),
('General Education','Mathematics','easy','What is the product of the first five prime numbers?','[{"key":"A","text":"2,310"},{"key":"B","text":"1,155"},{"key":"C","text":"30"},{"key":"D","text":"210"}]','A','First 5 primes: 2, 3, 5, 7, 11. Product = 2 × 3 × 5 × 7 × 11 = 2,310.','secondary'),
('General Education','Mathematics','medium','Simplify: (a²b³)² ÷ (ab)²','[{"key":"A","text":"a²b⁴"},{"key":"B","text":"a³b⁴"},{"key":"C","text":"a²b⁶"},{"key":"D","text":"ab²"}]','A','(a²b³)² = a⁴b⁶. (ab)² = a²b². a⁴b⁶ ÷ a²b² = a²b⁴.','secondary'),
('General Education','Mathematics','easy','Convert 3/5 to a percentage.','[{"key":"A","text":"35%"},{"key":"B","text":"60%"},{"key":"C","text":"0.6%"},{"key":"D","text":"30%"}]','B','3/5 = 3 ÷ 5 = 0.6 = 60%.','secondary'),
('General Education','Mathematics','medium','A number increased by 30% gives 78. What is the original number?','[{"key":"A","text":"50"},{"key":"B","text":"55"},{"key":"C","text":"60"},{"key":"D","text":"65"}]','C','Let x = original. x + 0.30x = 78 → 1.30x = 78 → x = 60.','secondary'),
('General Education','Mathematics','hard','What is 1 + 1/2 + 1/4 + 1/8 + 1/16 + ...?','[{"key":"A","text":"1.5"},{"key":"B","text":"1.75"},{"key":"C","text":"2"},{"key":"D","text":"Infinity"}]','C','This is an infinite geometric series with first term a = 1 and ratio r = 1/2. Sum = a/(1-r) = 1/(1-0.5) = 2.','secondary'),
('General Education','Mathematics','easy','What is the value of (-3)²?','[{"key":"A","text":"-9"},{"key":"B","text":"9"},{"key":"C","text":"-6"},{"key":"D","text":"6"}]','B','(-3)² = (-3) × (-3) = 9. The square of any non-zero number is positive.','secondary'),
('General Education','Mathematics','medium','A pipe can fill a tank in 3 hours; another drains it in 5 hours. If both are open, how long to fill the tank?','[{"key":"A","text":"7.5 hours"},{"key":"B","text":"8 hours"},{"key":"C","text":"3.75 hours"},{"key":"D","text":"1.875 hours"}]','A','Fill rate = 1/3 per hour, drain rate = 1/5 per hour. Net rate = 1/3 - 1/5 = 2/15 per hour. Time = 15/2 = 7.5 hours.','secondary'),
('General Education','Mathematics','easy','What is the square of 13?','[{"key":"A","text":"130"},{"key":"B","text":"156"},{"key":"C","text":"169"},{"key":"D","text":"196"}]','C','13² = 13 × 13 = 169.','secondary'),
('General Education','Mathematics','medium','If a : b = 2 : 3 and b : c = 4 : 5, find a : c.','[{"key":"A","text":"8:15"},{"key":"B","text":"2:5"},{"key":"C","text":"6:5"},{"key":"D","text":"10:9"}]','A','Make b equal: a:b = 8:12, b:c = 12:15. So a:c = 8:15.','secondary'),
('General Education','Mathematics','easy','Which of the following is an irrational number?','[{"key":"A","text":"0.333..."},{"key":"B","text":"√2"},{"key":"C","text":"1/7"},{"key":"D","text":"0.25"}]','B','Irrational numbers cannot be expressed as a ratio of integers. √2 ≈ 1.41421... is non-terminating and non-repeating.','secondary'),
('General Education','Mathematics','medium','Find the number of factors of 60.','[{"key":"A","text":"8"},{"key":"B","text":"10"},{"key":"C","text":"12"},{"key":"D","text":"14"}]','C','60 = 2² × 3 × 5. Number of factors = (2+1)(1+1)(1+1) = 3 × 2 × 2 = 12.','secondary'),
('General Education','Mathematics','medium','A train travels from City A to City B in 3 hours at 80 km/h. What is the distance?','[{"key":"A","text":"160 km"},{"key":"B","text":"200 km"},{"key":"C","text":"240 km"},{"key":"D","text":"280 km"}]','C','Distance = Speed × Time = 80 km/h × 3 h = 240 km.','secondary'),
('General Education','Mathematics','hard','What is the remainder when 17 × 19 × 21 is divided by 4?','[{"key":"A","text":"0"},{"key":"B","text":"1"},{"key":"C","text":"2"},{"key":"D","text":"3"}]','D','17 mod 4 = 1, 19 mod 4 = 3, 21 mod 4 = 1. Product mod 4 = 1 × 3 × 1 = 3.','secondary'),
('General Education','Mathematics','easy','How many significant figures does 0.00450 have?','[{"key":"A","text":"2"},{"key":"B","text":"3"},{"key":"C","text":"4"},{"key":"D","text":"5"}]','B','Leading zeros are not significant. The trailing zero after 5 IS significant. 0.00450 has 3 significant figures: 4, 5, and the final 0.','secondary'),
('General Education','Mathematics','medium','If 2x - 7 = 11, what is x?','[{"key":"A","text":"2"},{"key":"B","text":"7"},{"key":"C","text":"9"},{"key":"D","text":"18"}]','C','2x = 11 + 7 = 18. x = 18 ÷ 2 = 9.','secondary'),
('General Education','Mathematics','easy','What is the sum of interior angles of a triangle?','[{"key":"A","text":"90°"},{"key":"B","text":"180°"},{"key":"C","text":"270°"},{"key":"D","text":"360°"}]','B','The sum of all interior angles of any triangle is always 180°.','secondary'),
('General Education','Mathematics','medium','Find the value of x if 4x + 3 = 2x + 9.','[{"key":"A","text":"2"},{"key":"B","text":"3"},{"key":"C","text":"4"},{"key":"D","text":"6"}]','B','4x - 2x = 9 - 3 → 2x = 6 → x = 3.','secondary'),
('General Education','Mathematics','hard','A and B together can complete a task in 6 days. A alone takes 10 days. How long does B alone take?','[{"key":"A","text":"15 days"},{"key":"B","text":"16 days"},{"key":"C","text":"12 days"},{"key":"D","text":"20 days"}]','A','B''s rate = 1/6 - 1/10 = 5/30 - 3/30 = 2/30 = 1/15. B alone takes 15 days.','secondary'),
('General Education','Mathematics','easy','What is 2,500 in scientific notation?','[{"key":"A","text":"25 × 10²"},{"key":"B","text":"2.5 × 10³"},{"key":"C","text":"0.25 × 10⁴"},{"key":"D","text":"2.5 × 10²"}]','B','2,500 = 2.5 × 10³. Scientific notation requires exactly one non-zero digit before the decimal.','secondary');
